  rdata = mem[raddr];
end

module mem_sub(input clk, input we,
  input [3:0] waddr, raddr,
  input [7:0] wdata,
  output reg [7:0] rdata);
  reg [7:0] mem [0:15];
  always @(posedge clk) begin
    if (we) mem[waddr] <= wdata;
    rdata <= mem[raddr];
  end
endmodule
module memtest04(input clk, input we,
  input [3:0] a, b, input [7:0] d,
  output [7:0] q);
  mem_sub inst_m0(.clk(clk),.we(we),
    .waddr(a),.raddr(b),.wdata(d),.rdata(q));
endmodule
